export const sourceCode = "# Dialog\n\n모달 다이얼로그입니다. **controlled** 컴포넌트로, `open`과 `onOpenChange`로 열림 상태를 제어합니다.\n\n## Props\n\n| Prop                 | Type       | Default   | 설명 |\n| -------------------- | ---------- | --------- | ---- |\n| open                 | `boolean`  | —         | 열림 여부 |\n| onOpenChange         | `(open: boolean) => void` | — | 열림 상태 변경 시 호출 |\n| onClose              | `() => void` | —       | 닫힐 때 호출 |\n| title                | `string`   | —         | 제목 |\n| description          | `string`   | —         | 설명 텍스트 |\n| size                 | `\"small\"` \\| `\"medium\"` \\| `\"large\"` \\| `\"xlarge\"` \\| `\"full\"` | `\"medium\"` | 크기 |\n| rounded              | `\"small\"` \\| `\"medium\"` \\| `\"large\"` | `\"medium\"` | 모서리 반경 |\n| showCloseButton      | `boolean`  | `true`    | 닫기 버튼 표시 |\n| closeOnOverlayClick  | `boolean`  | `true`    | 오버레이 클릭 시 닫기 |\n| closeOnEscape        | `boolean`  | `true`    | Escape 키로 닫기 |\n| actions              | `DialogAction[]` | —   | 푸터 액션 버튼 목록 |\n| footer               | `ReactNode`| —         | 푸터 커스텀 |\n\n## 코드\n\n```tsx\nimport { useState } from \"react\";\nimport { Dialog, Button } from \"pine-design-system\";\n\nfunction Example() {\n  const [open, setOpen] = useState(false);\n  return (\n    <>\n      <Button onClick={() => setOpen(true)}>Open Dialog</Button>\n      <Dialog\n        open={open}\n        onOpenChange={setOpen}\n        title=\"Title\"\n        description=\"Optional description.\"\n        actions={[\n          { label: \"Cancel\", onClick: () => setOpen(false), variant: \"outline\" },\n          { label: \"Confirm\", onClick: () => setOpen(false) },\n        ]}\n      >\n        Dialog body content.\n      </Dialog>\n    </>\n  );\n}\n```";
